-- Helper: check if current JWT is admin/staff
CREATE OR REPLACE FUNCTION public.is_staff()
RETURNS boolean
LANGUAGE sql
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.profiles p
    WHERE p.id = auth.uid()
      AND p.role IN ('admin','superadmin','staff')
  )
$$;

-- Generic per-profile RLS (members can only see their own rows).
-- The service role bypasses RLS; the admin web uses the mobile backend with a
-- service-role token, so admin listings don't need dedicated policies here.
DO $$
DECLARE
  tbl TEXT;
  tables TEXT[] := ARRAY[
    'kyc','kyc_documents','savings','savings_goals','referrals',
    'wallets','transactions','bank_accounts','loans',
    'rollovers','investment_participations','notifications',
    'tickets','user_settings','watchlist'
  ];
BEGIN
  FOREACH tbl IN ARRAY tables LOOP
    EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', tbl || '_self_select', tbl);
    EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', tbl || '_self_modify', tbl);
    EXECUTE format(
      'CREATE POLICY %I ON public.%I FOR SELECT USING (profile_id = auth.uid() OR public.is_staff())',
      tbl || '_self_select', tbl
    );
    EXECUTE format(
      'CREATE POLICY %I ON public.%I FOR ALL USING (profile_id = auth.uid() OR public.is_staff()) WITH CHECK (profile_id = auth.uid() OR public.is_staff())',
      tbl || '_self_modify', tbl
    );
  END LOOP;
END$$;

-- Custom RLS for loan_qrs (uses applicant_id)
DROP POLICY IF EXISTS loan_qrs_self_select ON public.loan_qrs;
DROP POLICY IF EXISTS loan_qrs_self_modify ON public.loan_qrs;
CREATE POLICY loan_qrs_self_select ON public.loan_qrs FOR SELECT USING (applicant_id = auth.uid() OR public.is_staff());
CREATE POLICY loan_qrs_self_modify ON public.loan_qrs FOR ALL USING (applicant_id = auth.uid() OR public.is_staff()) WITH CHECK (applicant_id = auth.uid() OR public.is_staff());

-- Custom RLS for loan_guarantors (uses guarantor_id)
DROP POLICY IF EXISTS loan_guarantors_self_select ON public.loan_guarantors;
DROP POLICY IF EXISTS loan_guarantors_self_modify ON public.loan_guarantors;
CREATE POLICY loan_guarantors_self_select ON public.loan_guarantors FOR SELECT USING (guarantor_id = auth.uid() OR public.is_staff());
CREATE POLICY loan_guarantors_self_modify ON public.loan_guarantors FOR ALL USING (guarantor_id = auth.uid() OR public.is_staff()) WITH CHECK (guarantor_id = auth.uid() OR public.is_staff());

-- Custom RLS for ticket_messages (uses author_id)
DROP POLICY IF EXISTS ticket_messages_self_select ON public.ticket_messages;
DROP POLICY IF EXISTS ticket_messages_self_modify ON public.ticket_messages;
CREATE POLICY ticket_messages_self_select ON public.ticket_messages FOR SELECT USING (author_id = auth.uid() OR public.is_staff());
CREATE POLICY ticket_messages_self_modify ON public.ticket_messages FOR ALL USING (author_id = auth.uid() OR public.is_staff()) WITH CHECK (author_id = auth.uid() OR public.is_staff());

-- Custom RLS for ticket_attachments (uses uploaded_by)
DROP POLICY IF EXISTS ticket_attachments_self_select ON public.ticket_attachments;
DROP POLICY IF EXISTS ticket_attachments_self_modify ON public.ticket_attachments;
CREATE POLICY ticket_attachments_self_select ON public.ticket_attachments FOR SELECT USING (uploaded_by = auth.uid() OR public.is_staff());
CREATE POLICY ticket_attachments_self_modify ON public.ticket_attachments FOR ALL USING (uploaded_by = auth.uid() OR public.is_staff()) WITH CHECK (uploaded_by = auth.uid() OR public.is_staff());

-- Custom RLS for ticket_status_history (uses changed_by)
DROP POLICY IF EXISTS ticket_status_history_self_select ON public.ticket_status_history;
DROP POLICY IF EXISTS ticket_status_history_self_modify ON public.ticket_status_history;
CREATE POLICY ticket_status_history_self_select ON public.ticket_status_history FOR SELECT USING (changed_by = auth.uid() OR public.is_staff());
CREATE POLICY ticket_status_history_self_modify ON public.ticket_status_history FOR ALL USING (changed_by = auth.uid() OR public.is_staff()) WITH CHECK (changed_by = auth.uid() OR public.is_staff());

-- Profiles, referral_events, investment_pools, audit_logs, system_settings
-- have their own custom policies:
DROP POLICY IF EXISTS profiles_public_select ON public.profiles;
CREATE POLICY profiles_public_select ON public.profiles FOR SELECT USING (true);
DROP POLICY IF EXISTS profiles_self_insert ON public.profiles;
CREATE POLICY profiles_self_insert ON public.profiles FOR INSERT WITH CHECK (auth.uid() = id);
DROP POLICY IF EXISTS profiles_self_update ON public.profiles;
CREATE POLICY profiles_self_update ON public.profiles FOR UPDATE USING (auth.uid() = id OR public.is_staff());

DROP POLICY IF EXISTS referral_events_read ON public.referral_events;
CREATE POLICY referral_events_read ON public.referral_events FOR SELECT
  USING (referrer_id = auth.uid() OR referred_id = auth.uid() OR public.is_staff());
DROP POLICY IF EXISTS referral_events_write ON public.referral_events;
CREATE POLICY referral_events_write ON public.referral_events FOR ALL
  USING (referrer_id = auth.uid() OR public.is_staff())
  WITH CHECK (referrer_id = auth.uid() OR public.is_staff());

DROP POLICY IF EXISTS investment_pools_read ON public.investment_pools;
CREATE POLICY investment_pools_read ON public.investment_pools FOR SELECT USING (true);
DROP POLICY IF EXISTS investment_pools_write ON public.investment_pools;
CREATE POLICY investment_pools_write ON public.investment_pools FOR ALL USING (public.is_staff());

DROP POLICY IF EXISTS audit_logs_read ON public.audit_logs;
CREATE POLICY audit_logs_read ON public.audit_logs FOR SELECT USING (actor_id = auth.uid() OR public.is_staff());
DROP POLICY IF EXISTS audit_logs_insert ON public.audit_logs;
CREATE POLICY audit_logs_insert ON public.audit_logs FOR INSERT WITH CHECK (true);

DROP POLICY IF EXISTS system_settings_read ON public.system_settings;
CREATE POLICY system_settings_read ON public.system_settings FOR SELECT USING (true);
DROP POLICY IF EXISTS system_settings_write ON public.system_settings;
CREATE POLICY system_settings_write ON public.system_settings FOR ALL USING (public.is_staff());

-- -----------------------------------------------------------------------------
-- Trigger: auto-create dependent rows when a new auth user signs up
-- -----------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger AS $$
BEGIN
  INSERT INTO public.profiles (id, user_id, email, name, phone, role)
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'userId', 'USR-' || substr(NEW.id::text, 1, 8)),
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'name', ''),
    COALESCE(NEW.raw_user_meta_data->>'phone', ''),
    COALESCE(NEW.raw_user_meta_data->>'role', 'member')
  )
  ON CONFLICT (id) DO NOTHING;

  INSERT INTO public.wallets (profile_id)
  VALUES (NEW.id)
  ON CONFLICT (profile_id) DO NOTHING;

  INSERT INTO public.savings (profile_id)
  VALUES (NEW.id)
  ON CONFLICT (profile_id) DO NOTHING;

  INSERT INTO public.user_settings (profile_id)
  VALUES (NEW.id)
  ON CONFLICT (profile_id) DO NOTHING;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- -----------------------------------------------------------------------------
-- Convenience: auto-updated_at
-- -----------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS trigger AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DO $$
DECLARE
  tbl TEXT;
  tables TEXT[] := ARRAY[
    'profiles','kyc','savings','savings_goals','referrals','referral_events',
    'wallets','transactions','bank_accounts','loans','loan_qrs','loan_guarantors',
    'rollovers','investment_pools','investment_participations','notifications',
    'tickets','ticket_messages','user_settings','loan_repayments',
    'scheduled_notifications'
  ];
BEGIN
  FOREACH tbl IN ARRAY tables LOOP
    EXECUTE format('DROP TRIGGER IF EXISTS set_updated_at ON public.%I', tbl);
    EXECUTE format(
      'CREATE TRIGGER set_updated_at BEFORE UPDATE ON public.%I
       FOR EACH ROW EXECUTE FUNCTION public.set_updated_at()',
      tbl
    );
  END LOOP;
END$$;
